def average_score(scores: list[int]) -> int {
    total = 0;
    count = 0;
    for score in scores {
        total = total + score;
        count = count + 1;
    }
    if count == 0 {
        return 0;
    }
    return total / count;
}

with entry {
    print(average_score([80, 90, 70]));
}

