def bucket_counts(values: list[int]) -> list[int] {
    small = 0;
    medium = 0;
    large = 0;
    for value in values {
        if value < 10 {
            small = small + 1;
        } elif value < 100 {
            medium = medium + 1;
        } else {
            large = large + 1;
        }
    }
    return [small, medium, large];
}

with entry {
    print(bucket_counts([2, 9, 10, 50, 130]));
}

node Task {
    has title: str;
    has done: bool = false;
    has points: int = 0;

    def finish(points_awarded: int) -> int {
        self.done = true;
        self.points = points_awarded;
        return self.points;
    }
}

walker CompletedPoints {
    has total: int = 0;

    can scan with `root entry {
        visit [-->];
    }

    can scan with Task entry {
        if here.done {
            self.total = self.total + here.points;
        }
    }
}

with entry {
    t1 = Task(title="design");
    t2 = Task(title="build");
    t1.finish(5);
    root() ++> t1;
    root() ++> t2;
    w = CompletedPoints() spawn root();
    print(w.total);
}

node Service {
    has name: str;
    has healthy: bool;
    has latency: int;

    def status() -> str {
        if not self.healthy {
            return "down";
        }
        if self.latency > 200 {
            return "slow";
        }
        return "ok";
    }
}

def count_status(services: list[Service], wanted: str) -> int {
    count = 0;
    for service in services {
        if service.status() == wanted {
            count = count + 1;
        }
    }
    return count;
}

with entry {
    services = [Service(name="api", healthy=true, latency=90), Service(name="db", healthy=true, latency=250), Service(name="cache", healthy=false, latency=0)];
    print(count_status(services, "ok"));
    print(count_status(services, "slow"));
}

node Cost {
    has label: str;
    has amount: int;
}

node Project {
    has name: str;
    has budget: int;

    def remaining(spent: int) -> int {
        return self.budget - spent;
    }
}

walker CostTotal {
    has total: int = 0;

    can scan with Project entry {
        visit [-->];
    }

    can scan with Cost entry {
        self.total = self.total + here.amount;
    }
}

with entry {
    project = Project(name="launch", budget=1000);
    project ++> Cost(label="design", amount=150);
    project ++> Cost(label="hosting", amount=80);
    root() ++> project;
    w = CostTotal() spawn project;
    print(project.remaining(w.total));
}

node RequestLog {
    has path: str;
    has status: int;
    has millis: int;

    def is_error() -> bool {
        return self.status >= 500;
    }
}

def slow_errors(logs: list[RequestLog], limit: int) -> int {
    count = 0;
    for log in logs {
        if log.is_error() and log.millis > limit {
            count = count + 1;
        }
    }
    return count;
}

with entry {
    logs = [RequestLog(path="/", status=200, millis=30), RequestLog(path="/api", status=500, millis=300), RequestLog(path="/pay", status=502, millis=90)];
    print(slow_errors(logs, 100));
}
